## Adaptive Rejection Sampling (ARS)
## Implementation of Gilks, W. R., & Wild, P. (1992).
## Adaptive rejection sampling for Gibbs sampling. JRSS-C, 41(2), 337-348.
##
## Design: functional style. The public entry point is `ars()`. Discrete
## sub-tasks are factored into auxiliary functions prefixed with `ars_`.
## Densities are supplied on the natural (possibly unnormalised) scale, e.g.
## R's dnorm/dexp, and are transformed internally to the log scale h(x).

## ---------------------------------------------------------------------------
## Auxiliary: numerical helpers
## ---------------------------------------------------------------------------

# Log-density evaluator built from a user density function on a domain.
ars_make_logh <- function(density_function, lo, hi) {
  function(x) {
    d <- density_function(x)
    if (any(!is.finite(d)) || any(d < 0))
      stop("density_function returned non-finite or negative values")
    log(d)
  }
}

# Central (or one-sided near a boundary) finite-difference derivative of h.
ars_hprime <- function(logh, x, lo, hi) {
  vapply(x, function(xi) {
    dx <- 1e-6 * max(1, abs(xi))
    xl <- xi - dx
    xr <- xi + dx
    if (xl <= lo) return((logh(xi + dx) - logh(xi)) / dx)
    if (xr >= hi) return((logh(xi) - logh(xi - dx)) / dx)
    (logh(xr) - logh(xl)) / (2 * dx)
  }, numeric(1))
}

## ---------------------------------------------------------------------------
## Auxiliary: locate suitable starting abscissae
## ---------------------------------------------------------------------------

# On an unbounded side we need an abscissa whose tangent slope points back
# toward the mode (positive on the left, negative on the right) so the upper
# hull has finite mass. Search outward from a seed.
ars_find_slope_point <- function(logh, seed, direction, want_positive, lo, hi) {
  x <- seed
  step <- 1
  for (i in 1:500) {
    d <- ars_hprime(logh, x, lo, hi)
    if (is.finite(d) && ((want_positive && d > 1e-8) ||
                         (!want_positive && d < -1e-8)))
      return(x)
    x <- x + direction * step
    step <- step * 1.5
    if (x <= lo || x >= hi) break
  }
  stop("could not locate a valid starting abscissa; check the domain/density")
}

ars_init_abscissae <- function(logh, lo, hi) {
  # A finite interior seed.
  seed <- if (is.finite(lo) && is.finite(hi)) (lo + hi) / 2
          else if (is.finite(lo)) lo + 1
          else if (is.finite(hi)) hi - 1
          else 0

  # Left abscissa.
  if (is.finite(lo)) {
    xL <- lo + max(1e-3, (if (is.finite(hi)) (hi - lo) else 1) * 1e-2)
  } else {
    xL <- ars_find_slope_point(logh, seed, direction = -1,
                               want_positive = TRUE, lo, hi)
  }
  # Right abscissa.
  if (is.finite(hi)) {
    xR <- hi - max(1e-3, (if (is.finite(lo)) (hi - lo) else 1) * 1e-2)
  } else {
    xR <- ars_find_slope_point(logh, seed, direction = 1,
                               want_positive = FALSE, lo, hi)
  }
  if (xR <= xL) { m <- (xL + xR) / 2; xL <- m - 0.5; xR <- m + 0.5 }
  x <- sort(unique(c(xL, (xL + xR) / 2, xR)))
  x[is.finite(logh(x))]
}

## ---------------------------------------------------------------------------
## Auxiliary: build the upper/lower hulls from the current abscissae
## ---------------------------------------------------------------------------

ars_build_hull <- function(logh, x, lo, hi, concavity_tol = 1e-4) {
  x  <- sort(x)
  hx <- logh(x)
  if (any(!is.finite(hx)))
    stop("log-density is non-finite at an abscissa")
  hp <- ars_hprime(logh, x, lo, hi)
  k  <- length(x)

  # Log-concavity: tangent slopes must be non-increasing.
  if (k >= 2 && max(diff(hp)) > concavity_tol)
    stop("non-log-concave density detected: tangent slopes are increasing")

  # Intersection abscissae z of adjacent tangents; z[1]=lo, z[k+1]=hi.
  z <- numeric(k + 1)
  z[1] <- lo
  z[k + 1] <- hi
  if (k >= 2) {
    for (j in 1:(k - 1)) {
      if (abs(hp[j] - hp[j + 1]) < 1e-10) {
        z[j + 1] <- (x[j] + x[j + 1]) / 2
      } else {
        z[j + 1] <- (hx[j + 1] - hx[j] - x[j + 1] * hp[j + 1] +
                     x[j] * hp[j]) / (hp[j] - hp[j + 1])
      }
    }
  }

  # Per-segment tangent: u_j(t) = hx[j] + (t - x[j]) * hp[j] = m t + b.
  m <- hp
  b <- hx - x * hp

  # Log integral of exp(u_j) over [z[j], z[j+1]].
  logint <- numeric(k)
  for (j in 1:k) {
    a <- z[j]; bb <- z[j + 1]; mj <- m[j]
    if (abs(mj) < 1e-12) {
      logint[j] <- b[j] + log(bb - a)
    } else if (is.finite(a)) {
      logint[j] <- b[j] + mj * a + log(expm1(mj * (bb - a)) / mj)
    } else { # a = -Inf, requires mj > 0
      logint[j] <- b[j] + mj * bb - log(mj)
    }
  }
  if (any(!is.finite(logint)))
    stop("upper hull has infinite mass; density may not be log-concave/integrable")

  list(x = x, hx = hx, hp = hp, z = z, m = m, b = b,
       logint = logint, k = k)
}

## ---------------------------------------------------------------------------
## Auxiliary: sample from the upper hull; evaluate hulls at a point
## ---------------------------------------------------------------------------

ars_sample_upper <- function(hull) {
  # Choose a segment proportional to its mass (softmax on log integrals).
  p <- exp(hull$logint - max(hull$logint))
  j <- sample.int(hull$k, size = 1, prob = p)
  a <- hull$z[j]; bb <- hull$z[j + 1]; mj <- hull$m[j]
  w <- runif(1)
  if (abs(mj) < 1e-12) {
    a + w * (bb - a)
  } else if (is.finite(a)) {
    a + log1p(w * expm1(mj * (bb - a))) / mj
  } else { # a = -Inf, mj > 0
    bb + log(w) / mj
  }
}

ars_upper_eval <- function(hull, xs) {
  j <- findInterval(xs, hull$z, rightmost.closed = TRUE)
  j <- min(max(j, 1), hull$k)
  hull$m[j] * xs + hull$b[j]
}

ars_lower_eval <- function(hull, xs) {
  x <- hull$x; hx <- hull$hx
  if (xs < x[1] || xs > x[hull$k]) return(-Inf)
  j <- findInterval(xs, x)
  j <- min(j, hull$k - 1)
  ((x[j + 1] - xs) * hx[j] + (xs - x[j]) * hx[j + 1]) / (x[j + 1] - x[j])
}

## ---------------------------------------------------------------------------
## Public: the adaptive rejection sampler
## ---------------------------------------------------------------------------

ars <- function(density_function, domain, n = sample_count) {
  ## --- input validation -------------------------------------------------
  if (is.character(density_function)) {
    expr <- density_function
    density_function <- function(x) eval(parse(text = expr), list(x = x))
  }
  if (!is.function(density_function))
    stop("density_function must be a function (or an expression string in x)")
  if (missing(domain) || length(domain) != 2 || !is.numeric(domain))
    stop("domain must be a numeric vector of length 2: c(lower, upper)")
  lo <- domain[1]; hi <- domain[2]
  if (is.na(lo) || is.na(hi) || lo >= hi)
    stop("invalid domain: require domain[1] < domain[2]")
  if (missing(n) || length(n) != 1 || !is.numeric(n) || is.na(n) ||
      n <= 0 || n != floor(n))
    stop("n must be a single positive integer")
  n <- as.integer(n)

  logh <- ars_make_logh(density_function, lo, hi)

  # Sanity: density must be positive somewhere finite.
  test_pt <- if (is.finite(lo) && is.finite(hi)) (lo + hi) / 2
             else if (is.finite(lo)) lo + 1 else if (is.finite(hi)) hi - 1 else 0
  if (!is.finite(logh(test_pt)))
    stop("density is not positive/finite at an interior point of the domain")

  ## --- initialise -------------------------------------------------------
  x <- ars_init_abscissae(logh, lo, hi)
  if (length(x) < 2)
    stop("failed to initialise abscissae")
  hull <- ars_build_hull(logh, x, lo, hi)

  ## --- adaptive sampling loop ------------------------------------------
  out <- numeric(n)
  count <- 0L
  max_abscissae <- 500L
  guard <- 0L
  while (count < n) {
    guard <- guard + 1L
    if (guard > 100L * n + 10000L)
      stop("sampling failed to converge; check the density/domain")

    xs <- ars_sample_upper(hull)
    if (!is.finite(xs) || xs < lo || xs > hi) next
    uval <- ars_upper_eval(hull, xs)
    lval <- ars_lower_eval(hull, xs)
    w <- runif(1)

    if (w <= exp(lval - uval)) {
      # Squeeze test accepted.
      count <- count + 1L; out[count] <- xs
    } else {
      hxs <- logh(xs)
      # Log-concavity check: h must lie below the upper hull.
      if (hxs - uval > 1e-4)
        stop("non-log-concave density detected: h(x) exceeds the upper hull")
      if (w <= exp(hxs - uval)) {
        count <- count + 1L; out[count] <- xs
      }
      # Adapt: incorporate the new abscissa and rebuild the hull.
      if (length(hull$x) < max_abscissae) {
        x <- sort(c(hull$x, xs))
        hull <- ars_build_hull(logh, x, lo, hi)
      }
    }
  }
  out
}

## ---------------------------------------------------------------------------
## Formal testing
## ---------------------------------------------------------------------------

ars_report <- function(name, passed, mu, sigma, extra = "") {
  cat(sprintf("%s: %s | mean = %.4f, sd = %.4f%s\n",
              name, if (passed) "PASS" else "FAIL", mu, sigma,
              if (nzchar(extra)) paste0(" | ", extra) else ""))
  invisible(passed)
}

test <- function() {
  set.seed(1992)
  cat("=== Adaptive Rejection Sampling: formal tests ===\n")
  all_ok <- TRUE

  ## 1. Standard normal ---------------------------------------------------
  cat("\n[1] Sampling N(0,1) on (-Inf, Inf), comparing to known truth...\n")
  s <- ars(dnorm, c(-Inf, Inf), n = 3000)
  mu <- mean(s); sigma <- sd(s)
  ks <- suppressWarnings(ks.test(s, "pnorm"))
  ok <- abs(mu - 0) < 0.1 && abs(sigma - 1) < 0.1 && ks$p.value > 0.01
  all_ok <- all_ok && ok
  write.table(s, "/app/normal_samples.txt", row.names = FALSE, col.names = FALSE)
  ars_report("NORMAL", ok, mu, sigma,
             sprintf("KS p = %.3f (truth: mean 0, sd 1)", ks$p.value))

  ## 2. Exponential(1) ----------------------------------------------------
  cat("\n[2] Sampling Exp(1) on (0, Inf), comparing to known truth...\n")
  s <- ars(function(x) dexp(x, rate = 1), c(0, Inf), n = 3000)
  mu <- mean(s); sigma <- sd(s)
  ks <- suppressWarnings(ks.test(s, "pexp"))
  ok <- abs(mu - 1) < 0.1 && abs(sigma - 1) < 0.1 && ks$p.value > 0.01
  all_ok <- all_ok && ok
  write.table(s, "/app/exponential_samples.txt", row.names = FALSE, col.names = FALSE)
  ars_report("EXPONENTIAL", ok, mu, sigma,
             sprintf("KS p = %.3f (truth: mean 1, sd 1)", ks$p.value))

  ## 3. Normal with non-standard params (module/robustness) --------------
  cat("\n[3] Sampling N(5,2^2) on (-Inf, Inf), comparing to known truth...\n")
  s <- ars(function(x) dnorm(x, mean = 5, sd = 2), c(-Inf, Inf), n = 3000)
  mu <- mean(s); sigma <- sd(s)
  ok <- abs(mu - 5) < 0.2 && abs(sigma - 2) < 0.2
  all_ok <- all_ok && ok
  ars_report("NORMAL_5_2", ok, mu, sigma, "truth: mean 5, sd 2")

  ## 4. Truncated normal on a bounded domain -----------------------------
  cat("\n[4] Sampling N(0,1) truncated to [-1, 1]...\n")
  s <- ars(dnorm, c(-1, 1), n = 3000)
  mu <- mean(s); sigma <- sd(s)
  ok <- all(s >= -1 & s <= 1) && abs(mu) < 0.1
  all_ok <- all_ok && ok
  ars_report("TRUNC_NORMAL", ok, mu, sigma, "truth: symmetric about 0, in [-1,1]")

  ## 5. Input validation --------------------------------------------------
  cat("\n[5] Input validation (negative n, invalid domain)...\n")
  e1 <- inherits(try(ars(dnorm, c(-Inf, Inf), n = -5), silent = TRUE), "try-error")
  e2 <- inherits(try(ars(dnorm, c(2, 1), n = 10), silent = TRUE), "try-error")
  e3 <- inherits(try(ars(dnorm, c(0, 1, 2), n = 10), silent = TRUE), "try-error")
  e4 <- inherits(try(ars("not_a_fn_object", c(0, 1), n = 10), silent = TRUE), "try-error")
  ok <- e1 && e2 && e3
  all_ok <- all_ok && ok
  cat(sprintf("VALIDATION: %s | rejected negative n: %s, bad domain: %s, bad length: %s\n",
              if (ok) "PASS" else "FAIL", e1, e2, e3))

  ## 6. Non-log-concave detection ----------------------------------------
  cat("\n[6] Non-log-concave density detection (Cauchy / t)...\n")
  err <- try(ars(function(x) dcauchy(x), c(-Inf, Inf), n = 3000), silent = TRUE)
  ok <- inherits(err, "try-error")
  all_ok <- all_ok && ok
  cat(sprintf("NON_LOG_CONCAVE: %s | error raised: %s\n",
              if (ok) "PASS" else "FAIL", ok))

  cat(sprintf("\n=== OVERALL: %s ===\n", if (all_ok) "PASS" else "FAIL"))
  invisible(all_ok)
}

# Allow `Rscript ars.R` to run the test suite directly.
if (identical(environment(), globalenv()) &&
    !interactive() && sys.nframe() == 0L) {
  # no auto-run on source; call test() explicitly.
}

